  "inlineSchema": "/**\n * =====================================================\n * ⚙️ CONFIGURAÇÃO\n * =====================================================\n */\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n/**\n * =====================================================\n * 🏢 COMPANY (MULTI-TENANT)\n * =====================================================\n */\n\nmodel Company {\n  id   String @id @default(uuid())\n  name String\n\n  memberships Membership[]\n  posts       Post[]\n  invites     Invite[]\n\n  createdAt DateTime @default(now())\n\n  @@index([name])\n}\n\n/**\n * =====================================================\n * 👤 USER\n * =====================================================\n */\n\nmodel User {\n  id       String  @id @default(uuid())\n  email    String  @unique\n  name     String?\n  password String\n\n  memberships Membership[]\n\n  posts         Post[]\n  permissions   UserPermission[]\n  notifications Notification[]\n  comments      Comment[]\n  audits        AuditLog[]\n  refreshTokens RefreshToken[]\n\n  createdAt DateTime @default(now())\n\n  @@index([email])\n}\n\n/**\n * =====================================================\n * 🔗 MEMBERSHIP (CORE MULTI-TENANT)\n * =====================================================\n * - Um usuário pode ter papéis diferentes por empresa\n */\n\nmodel Membership {\n  id        String @id @default(cuid())\n  userId    String\n  companyId String\n  roleId    String\n\n  user    User    @relation(fields: [userId], references: [id])\n  company Company @relation(fields: [companyId], references: [id])\n  role    Role    @relation(fields: [roleId], references: [id])\n\n  // 🔔 controle de leitura (timeline/notificações)\n  lastReadAt DateTime?\n\n  // 🧠 auditoria\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, companyId])\n  @@index([userId])\n  @@index([companyId])\n}\n\n/**\n * =====================================================\n * 🔐 RBAC (ROLE BASED ACCESS CONTROL)\n * =====================================================\n */\n\nmodel Role {\n  id          String           @id @default(cuid())\n  name        String           @unique\n  permissions RolePermission[]\n  memberships Membership[]\n\n  createdAt DateTime @default(now())\n  invites   Invite[]\n}\n\n/**\n * 🔐 PERMISSIONS (DINÂMICAS)\n */\n\nmodel Permission {\n  id   String @id @default(cuid())\n  name String @unique\n\n  roles           RolePermission[]\n  userPermissions UserPermission[]\n}\n\n/**\n * 🔗 RELAÇÃO ROLE ↔ PERMISSION\n */\n\nmodel RolePermission {\n  roleId       String\n  permissionId String\n\n  role       Role       @relation(fields: [roleId], references: [id])\n  permission Permission @relation(fields: [permissionId], references: [id])\n\n  @@id([roleId, permissionId])\n}\n\n/**\n * =====================================================\n * 🔐 PERMISSÕES POR USUÁRIO (OVERRIDE OPCIONAL)\n * =====================================================\n */\n\nmodel UserPermission {\n  id           String @id @default(uuid())\n  userId       String\n  companyId    String\n  permissionId String\n\n  user       User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  permission Permission @relation(fields: [permissionId], references: [id])\n\n  @@index([userId, companyId])\n}\n\n/**\n * =====================================================\n * 📝 POSTS\n * =====================================================\n */\n\nmodel Post {\n  id       Int     @id @default(autoincrement())\n  title    String\n  content  String\n  imageUrl String?\n\n  status PostStatus @default(DRAFT)\n\n  authorId String\n  author   User   @relation(fields: [authorId], references: [id])\n\n  companyId String\n  company   Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n\n  scheduledDate DateTime?\n\n  approvedBy String?\n  approvedAt DateTime?\n\n  comments Comment[]\n  audits   AuditLog[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([companyId])\n}\n\n/**\n * =====================================================\n * 📊 STATUS DO POST\n * =====================================================\n */\n\nenum PostStatus {\n  DRAFT\n  SCHEDULED\n  PUBLISHED\n  APPROVED\n  REJECTED\n}\n\n/**\n * =====================================================\n * 🔔 NOTIFICAÇÕES\n * =====================================================\n */\n\nmodel Notification {\n  id      String  @id @default(uuid())\n  userId  String\n  message String\n  read    Boolean @default(false)\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n}\n\n/**\n * =====================================================\n * 💬 COMENTÁRIOS\n * =====================================================\n */\n\nmodel Comment {\n  id      Int    @id @default(autoincrement())\n  content String\n\n  postId Int\n  userId String\n\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([postId])\n}\n\n/**\n * =====================================================\n * 🧾 AUDITORIA\n * =====================================================\n */\n\nmodel AuditLog {\n  id     Int    @id @default(autoincrement())\n  action String\n\n  postId Int\n  userId String\n\n  meta Json?\n\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n}\n\n/**\n * =====================================================\n * 🔐 REFRESH TOKEN\n * =====================================================\n */\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  userId    String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n}\n\n/**\n * =====================================================\n * ✉️ INVITES (CONVITE PARA EMPRESA)\n * =====================================================\n */\n\nmodel Invite {\n  id        String @id @default(uuid())\n  email     String\n  companyId String\n  roleId    String\n  token     String @unique\n\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  company Company @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  role    Role    @relation(fields: [roleId], references: [id])\n\n  @@index([companyId])\n}\n",
